#include <bits/stdc++.h>
using namespace std;

const int N=1e4+10,M=1e5+10;

int n,m,a[N];
int head[N],ver[M],nxt[M],tot;
int num,dfn[N],low[N],stk[N],top;
int cnt,c[N],sum[N],d[N],f[N],ans;
bool ins[N];
vector<int> g[N];

void add(int x,int y){
    ver[++tot]=y,nxt[tot]=head[x],head[x]=tot;
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    stk[++top]=x,ins[x]=1;
    for(int i=head[x];i;i=nxt[i])
        if(!dfn[ver[i]]){
            tarjan(ver[i]);
            low[x]=min(low[x],low[ver[i]]);
        }else if(ins[ver[i]])
            low[x]=min(low[x],dfn[ver[i]]);
    if(dfn[x]==low[x]){
        cnt++;
        int t;
        do{
            t=stk[top--],ins[t]=0;
            c[t]=cnt,sum[cnt]+=a[t];
        }while(t!=x);
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    	scanf("%d",&a[i]);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        add(u,v);
    }
    for(int i=1;i<=n;i++)
        if(!dfn[i])
            tarjan(i);
    for(int i=1;i<=n;i++)
        for(int j=head[i];j;j=nxt[j])
            if(c[i]!=c[ver[j]])
                g[c[i]].push_back(c[ver[j]]),d[c[ver[j]]]++;
    queue<int> q;
    for(int i=1;i<=cnt;i++){
        f[i]=sum[i];
        if(!d[i])
            q.push(i);
    }
    while(q.size()){
        int x=q.front();
        q.pop();
        ans=max(ans,f[x]);
        for(int y:g[x]){
            f[y]=max(f[y],f[x]+sum[y]);
            if(!--d[y])
                q.push(y);
        }
    }
    printf("%d",ans);
    return 0;
}
